169	export function runScenario(steps: Step[]): unknown[] {
170	  return steps.map((step, index) => {
171	    if (step.type === "claim") {
172	      return claimResult(step, steps);
173	    }
174	    return quoteResult(step, hasPriorQuote(steps, index));
